  lem:gr_chartTransition_self, def:gr_away_pullback_iso,
  lem:gr_awayPullbackIso_inv_fst, lem:gr_awayPullbackIso_inv_snd,
  def:gr_away_mul_comm_equiv, def:gr_cocycle_theta_ij}

